import React, { useEffect, useState } from 'react';
import Navbar from '../../components/Navbar';
import api from '../../api/axiosInstance';
import styles from './AdminPages.module.css';

const ManagePackagesPage = () => {

  const [packages, setPackages] = useState([]);
  const [destinations, setDestinations] = useState([]);
  const [loading, setLoading] = useState(true);

  const [formData, setFormData] = useState({
    name: '',
    destination: '',
    duration: '',
    price: '',
    availableSlots: '',
    description: '',
    transportation: '',
    sightseeing: '',
    accommodation: '',
    meals: '',
    itinerary: ''
  });

  useEffect(() => {
    load();
    loadDestinations();
  }, []);

  const load = async () => {
    const res = await api.get('/packages');
    setPackages(res.data.data);
    setLoading(false);
  };

  const loadDestinations = async () => {
    const res = await api.get('/destinations');
    setDestinations(res.data.data);
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const addPackage = async (e) => {
    e.preventDefault();

    const payload = {
      ...formData,
      transportation: formData.transportation.split(','),
      sightseeing: formData.sightseeing.split(','),
      accommodation: formData.accommodation.split(','),
      meals: formData.meals.split(','),
      itinerary: formData.itinerary.split(',')
    };

    await api.post('/packages', payload);
    alert("✨ Package Added Successfully!");

    setFormData({
      name: '',
      destination: '',
      duration: '',
      price: '',
      availableSlots: '',
      description: '',
      transportation: '',
      sightseeing: '',
      accommodation: '',
      meals: '',
      itinerary: ''
    });

    load();
  };

  return (
    <>
      <Navbar />

      <div className={styles.container}>

        <h1 className={styles.heading}>✨ Manage Travel Packages</h1>

        {/* FORM */}
        <div className={styles.glassCard}>
          <h2>Add New Package</h2>

          <form onSubmit={addPackage} className={styles.form}>

            <input name="name" placeholder="Package Name" value={formData.name} onChange={handleChange} />

            <select name="destination" value={formData.destination} onChange={handleChange}>
              <option value="">Select Destination</option>
              {destinations.map(d => (
                <option key={d._id} value={d._id}>{d.name}</option>
              ))}
            </select>

            <input name="duration" placeholder="Duration (4N/5D)" value={formData.duration} onChange={handleChange} />
            <input name="price" type="number" placeholder="Price ₹" value={formData.price} onChange={handleChange} />
            <input name="availableSlots" type="number" placeholder="Slots" value={formData.availableSlots} onChange={handleChange} />

            <textarea name="description" placeholder="Description" value={formData.description} onChange={handleChange} />

            <textarea name="transportation" placeholder="🚗 Transportation (comma separated)" value={formData.transportation} onChange={handleChange} />
            <textarea name="sightseeing" placeholder="🎡 Sightseeing (comma separated)" value={formData.sightseeing} onChange={handleChange} />
            <textarea name="accommodation" placeholder="🏨 Accommodation (comma separated)" value={formData.accommodation} onChange={handleChange} />
            <textarea name="meals" placeholder="🍽 Meals (comma separated)" value={formData.meals} onChange={handleChange} />
            <textarea name="itinerary" placeholder="🗓 Itinerary (comma separated)" value={formData.itinerary} onChange={handleChange} />

            <button className={styles.btn}>➕ Add Package</button>

          </form>
        </div>

        {/* TABLE */}
        <div className={styles.glassCard}>
          <h2>📦 Existing Packages</h2>

          {loading ? <p>Loading...</p> : (
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Destination</th>
                  <th>Duration</th>
                  <th>Price</th>
                </tr>
              </thead>

              <tbody>
                {packages.map(p => (
                  <tr key={p._id}>
                    <td>{p.name}</td>
                    <td>{p.destination?.name}</td>
                    <td>{p.duration}</td>
                    <td>₹{p.price}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}

        </div>

      </div>
    </>
  );
};

export default ManagePackagesPage;
